const {
  tweet: tweetSchema,
  getTweets: getTweetsSchema,
  getUserTweets: getUserTweetsSchema
} = require('./schemas')

module.exports = async function (fastify, opts) {
  // All APIs are under authentication here!
  fastify.addHook('preHandler', fastify.authPreHandler)

  fastify.post('/', { schema: tweetSchema }, addTwitterHandler)
  fastify.get('/', { schema: getTweetsSchema }, getTwitterHandler)
  fastify.get('/:userIds', { schema: getUserTweetsSchema }, getUserTweetsHandler)
}

module.exports[Symbol.for('plugin-meta')] = {
  decorators: {
    fastify: [
      'authPreHandler',
      'tweetService'
    ]
  }
}

async function addTwitterHandler (req, reply) {
  const { text } = req.body
  await this.tweetService.addTweet(req.user, text)
  reply.code(204)
}

async function getTwitterHandler (req, reply) {
  return this.tweetService.fetchTweets([req.user._id])
}

async function getUserTweetsHandler (req, reply) {
  const userIds = req.params.userIds.split(',')
  return this.tweetService.fetchTweets(userIds)
}

'use strict'

function convertUserIdToStringInTweet (t) {
  t.user._id = t.user._id.toString('hex')
  return t
}

class TweetService {
  constructor (tweetCollection) {
    this.tweetCollection = tweetCollection
  }

  async fetchTweets (userIds) {
    const tweets = await this.tweetCollection.find({
      'user._id': { $in: userIds }
    }).sort({createdAt: -1}).toArray()
    return tweets.map(convertUserIdToStringInTweet)
  }

  async addTweet (user, text) {
    await this.tweetCollection.insertOne({
      user,
      text,
      createdAt: new Date()
    })
  }

  async ensureIndexes (db) {
    await db.command({
      'collMod': this.tweetCollection.collectionName,
      validator: {
        user: { $type: 'object' },
        'user._id': { $type: 'string' },
        'user.username': { $type: 'string' },
        text: { $type: 'string' }
      }
    })
    await this.tweetCollection.createIndex({ 'user._id': 1 })
  }
}

module.exports = TweetService

